var resp = httpGet(args.url, {'User-Agent': 'AT-WebScraper/1.0'});
// httpGet auto-parses JSON bodies; coerce to string so .replace works on JSON pages too.
var html = (typeof resp.body === 'string') ? resp.body : JSON.stringify(resp.body);
// Strip HTML tags to get text content
var text = html.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '');
text = text.replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '');
text = text.replace(/<[^>]+>/g, ' ');
text = text.replace(/\s+/g, ' ').trim();
// Truncate if very long
if (text.length > 10000) text = text.substring(0, 10000) + '... (truncated)';
return JSON.stringify({url: args.url, status: resp.status, length: text.length, content: text}, null, 2);

var resp = httpGet(args.url, {'User-Agent': 'AT-WebScraper/1.0'});
// httpGet auto-parses JSON bodies; coerce to string so the regex matcher works on JSON pages too.
var html = (typeof resp.body === 'string') ? resp.body : JSON.stringify(resp.body);
var links = [];
var re = /<a[^>]+href=["']([^"']+)["'][^>]*>(.*?)<\/a>/gi;
var match;
while ((match = re.exec(html)) !== null) {
  var href = match[1];
  var text = match[2].replace(/<[^>]+>/g, '').trim();
  if (href && !href.startsWith('#') && !href.startsWith('javascript:')) {
    // Resolve relative URLs
    if (href.startsWith('/')) href = args.url.replace(/(https?:\/\/[^\/]+).*/, '$1') + href;
    links.push({href: href, text: text || ''});
  }
}
return JSON.stringify({url: args.url, count: links.length, links: links}, null, 2);
